UPDATE cliente
SET nombre = #{nombre}, apellidoPaterno = #{apellidoPaterno}, apellidoMaterno = #{apellidoMaterno},
    calle = #{calle}, numero = #{numero}, colonia = #{colonia}, codigoPostal = #{codigoPostal},
    ciudad = #{ciudad}, estado = #{estado}, telefono = #{telefono}, correo = #{correo}
WHERE idCliente = #{idCliente}
